import { randomUUID } from 'crypto';
import { Router, type Request, type Response } from 'express';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';

const commentsRouter = Router();

function isUuid(value: string): boolean {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(value);
}

function parseUuid(value: unknown): string | null {
  return typeof value === 'string' && isUuid(value) ? value : null;
}

function mapCommentRow(row: any) {
  return {
    id: row.id,
    document_id: row.document_id,
    comment_id: row.comment_id,
    parent_id: row.parent_id,
    author_id: row.author_id,
    content: row.content,
    resolved_at: row.resolved_at,
    resolved_by: row.resolved_by ?? null,
    deleted_at: row.deleted_at ?? null,
    created_at: row.created_at,
    updated_at: row.updated_at,
  };
}

async function getCommentWithWorkspace(id: string) {
  return pool.query('SELECT c.*, d.workspace_id FROM comments c JOIN documents d ON d.id = c.document_id WHERE c.id = $1', [id]);
}

async function isWorkspaceAdmin(workspaceId: string, userId: string): Promise<boolean> {
  const result = await pool.query(
    'SELECT role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2',
    [workspaceId, userId]
  );
  return result.rows[0]?.role === 'admin' || result.rows[0]?.role === 'owner';
}

commentsRouter.get('/documents/:id/comments', authMiddleware, async (req: Request, res: Response) => {
  const documentId = parseUuid(req.params.id);
  if (!documentId) return res.status(400).json({ error: 'Invalid document id' });

  const document = await pool.query('SELECT id FROM documents WHERE id = $1 AND workspace_id = $2', [documentId, req.workspaceId]);
  if (document.rowCount === 0) return res.status(404).json({ error: 'Document not found' });

  const rows = await pool.query(
    'SELECT id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at FROM comments WHERE document_id = $1 AND deleted_at IS NULL ORDER BY comment_id ASC, created_at ASC',
    [documentId]
  );

  const threads = new Map<string, { comment_id: string; root: ReturnType<typeof mapCommentRow> | null; replies: ReturnType<typeof mapCommentRow>[] }>();
  for (const row of rows.rows) {
    const comment = mapCommentRow(row);
    const thread = threads.get(comment.comment_id) ?? { comment_id: comment.comment_id, root: null, replies: [] };
    if (comment.parent_id === null) thread.root = comment;
    else thread.replies.push(comment);
    threads.set(comment.comment_id, thread);
  }

  return res.json({
    comments: Array.from(threads.values()).map((thread) => ({
      comment_id: thread.comment_id,
      root: thread.root,
      replies: thread.replies,
    })),
  });
});

commentsRouter.post('/documents/:id/comments', authMiddleware, async (req: Request, res: Response) => {
  const documentId = parseUuid(req.params.id);
  if (!documentId) return res.status(400).json({ error: 'Invalid document id' });

  const document = await pool.query('SELECT id, workspace_id FROM documents WHERE id = $1', [documentId]);
  if (document.rowCount === 0) return res.status(404).json({ error: 'Document not found' });
  if (document.rows[0].workspace_id !== req.workspaceId) return res.status(403).json({ error: 'Forbidden' });

  const content = typeof req.body?.content === 'string' ? req.body.content.trim() : '';
  if (!content) return res.status(400).json({ error: 'content is required' });

  const parentId = req.body?.parent_id === undefined || req.body?.parent_id === null ? null : parseUuid(req.body.parent_id);
  if (req.body?.parent_id != null && !parentId) return res.status(400).json({ error: 'Invalid parent_id' });

  const threadCommentId = req.body?.comment_id == null ? randomUUID() : parseUuid(req.body.comment_id);
  if (req.body?.comment_id != null && !threadCommentId) return res.status(400).json({ error: 'Invalid comment_id' });

  if (parentId) {
    const parent = await pool.query('SELECT id, comment_id, document_id FROM comments WHERE id = $1', [parentId]);
    if (parent.rowCount === 0 || parent.rows[0].document_id !== documentId) return res.status(404).json({ error: 'Parent comment not found' });
    const inserted = await pool.query(
      'INSERT INTO comments (id, document_id, comment_id, parent_id, author_id, content) VALUES ($1, $2, $3, $4, $5, $6) RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at',
      [randomUUID(), documentId, parent.rows[0].comment_id, parentId, req.userId!, content]
    );
    return res.status(201).json(mapCommentRow(inserted.rows[0]));
  }

  const inserted = await pool.query(
    'INSERT INTO comments (id, document_id, comment_id, parent_id, author_id, content) VALUES ($1, $2, $3, NULL, $4, $5) RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at',
    [randomUUID(), documentId, threadCommentId, req.userId!, content]
  );
  return res.status(201).json(mapCommentRow(inserted.rows[0]));
});

commentsRouter.patch('/comments/:id', authMiddleware, async (req: Request, res: Response) => {
  const id = parseUuid(req.params.id);
  if (!id) return res.status(400).json({ error: 'Invalid comment id' });

  const content = typeof req.body?.content === 'string' ? req.body.content.trim() : '';
  if (!content) return res.status(400).json({ error: 'content is required' });

  const existing = await getCommentWithWorkspace(id);
  if (existing.rowCount === 0) return res.status(404).json({ error: 'Comment not found' });
  if (existing.rows[0].workspace_id !== req.workspaceId) return res.status(403).json({ error: 'Forbidden' });
  if (existing.rows[0].author_id !== req.userId) return res.status(403).json({ error: 'Only the author can edit this comment' });

  const result = await pool.query('UPDATE comments SET content = $2, updated_at = NOW() WHERE id = $1 RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at', [id, content]);
  return res.json(mapCommentRow(result.rows[0]));
});

commentsRouter.post('/comments/:id/resolve', authMiddleware, async (req: Request, res: Response) => {
  const id = parseUuid(req.params.id);
  if (!id) return res.status(400).json({ error: 'Invalid comment id' });

  const existing = await getCommentWithWorkspace(id);
  if (existing.rowCount === 0) return res.status(404).json({ error: 'Comment not found' });
  if (existing.rows[0].workspace_id !== req.workspaceId) return res.status(403).json({ error: 'Forbidden' });

  const result = await pool.query('UPDATE comments SET resolved_at = NOW(), resolved_by = $2, updated_at = NOW() WHERE id = $1 RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at', [id, req.userId]);
