    return res.status(400).json({ error: 'One or more target documents not found or not visible' });
  }

  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);

    if (linkIds.length > 0) {
      const values = linkIds.map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`).join(', ');
      const params = linkIds.flatMap((targetId) => [sourceId, targetId]);
      await client.query(
        `INSERT INTO document_links (source_id, target_id)
