  const filePath = join(LOCAL_UPLOADS_DIR, fileRow.rows[0].s3_key);
  await mkdir(dirname(filePath), { recursive: true });
  await writeFile(filePath, uploadedFile.buffer);

  const downloadUrl = buildPublicDownloadUrl(fileId);
  await pool.query(`UPDATE files SET status = 'uploaded', uploaded_at = NOW(), cdn_url = $1, updated_at = NOW() WHERE id = $2`, [downloadUrl, fileId]);
