import { Router, Request, Response } from 'express';
import multer from 'multer';
import { pool } from '../db/client.js';
import { z } from 'zod';
import { randomUUID } from 'crypto';
import { mkdir, writeFile } from 'fs/promises';
import path, { basename, dirname, join } from 'path';
import { authMiddleware } from '../middleware/auth.js';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { getAppEnvConfig } from '../config/env.js';
import { usesS3Storage } from '../utils/runtime-storage.js';

const MAX_FILE_SIZE = 1024 * 1024 * 1024;
const PRESIGNED_URL_EXPIRES_IN = 15 * 60;
const AWS_REGION = process.env.AWS_REGION || 'us-east-1';
const { uploadsDir: LOCAL_UPLOADS_DIR } = getAppEnvConfig();
const S3_BUCKET_NAME = process.env.S3_UPLOADS_BUCKET || null;

const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const BLOCKED_EXTENSIONS = new Set([
  '.exe', '.bat', '.cmd', '.com', '.msi', '.scr', '.pif', '.vbs', '.vbe', '.js', '.jse', '.ws', '.wsf', '.wsc', '.wsh',
  '.dll', '.sys', '.drv', '.cpl', '.ocx', '.lnk', '.inf', '.reg', '.msc', '.app', '.dmg', '.pkg', '.sh', '.bash', '.deb',
  '.rpm', '.run', '.jar', '.ps1', '.psm1', '.psd1',
]);

const uploadRequestSchema = z.object({
  filename: z.string().min(1).max(255),
  mimeType: z.string().min(1).max(100),
  sizeBytes: z.coerce.number().int().positive().max(MAX_FILE_SIZE),
});

const uploadRequestResponseSchema = z.object({
  fileId: z.string().uuid(),
  status: z.literal('pending'),
  uploadUrl: z.string().url().nullable(),
  uploadEndpoint: z.string().optional(),
  method: z.enum(['PUT', 'POST']),
  expiresInSeconds: z.number().int().positive().optional(),
  downloadUrl: z.string().nullable(),
  metadataUrl: z.string(),
});

const fileMetadataResponseSchema = z.object({
  id: z.string().uuid(),
  filename: z.string(),
  mimeType: z.string(),
  sizeBytes: z.number().int(),
  s3Key: z.string(),
  status: z.enum(['pending', 'processing', 'uploaded', 'failed']),
  createdAt: z.string(),
  uploadedAt: z.string().nullable(),
  failedAt: z.string().nullable(),
  errorMessage: z.string().nullable(),
  downloadUrl: z.string().nullable(),
});

const localUploadMiddleware = multer({ storage: multer.memoryStorage(), limits: { fileSize: MAX_FILE_SIZE } });

function isDangerousExtension(filename: string): boolean {
  const clean = basename(filename).toLowerCase();
  const dot = clean.lastIndexOf('.');
  return dot !== -1 && BLOCKED_EXTENSIONS.has(clean.slice(dot));
}

function buildDownloadUrl(fileId: string): string {
  return `/api/files/${fileId}`;
}

function buildUploadPath(fileId: string): string {
  return `/api/files/upload/${fileId}`;
}

function buildStorageKey(fileId: string, filename: string): string {
  return `${fileId}${path.extname(filename)}`;
}

async function createS3PresignedUrl(s3Key: string, contentType: string, sizeBytes: number): Promise<string> {
  if (!S3_BUCKET_NAME) throw new Error('S3 bucket not configured');
  const s3Client = new S3Client({ region: AWS_REGION });
  const command = new PutObjectCommand({ Bucket: S3_BUCKET_NAME, Key: s3Key, ContentType: contentType, ContentLength: sizeBytes });
  return getSignedUrl(s3Client, command, { expiresIn: PRESIGNED_URL_EXPIRES_IN });
}

export const filesRouter = Router();

filesRouter.post('/upload-request', authMiddleware, async (req: Request, res: Response) => {
  const parsed = uploadRequestSchema.safeParse(req.body);
  if (!parsed.success) {
    res.status(400).json({ error: 'Invalid input', details: parsed.error.flatten() });
    return;
  }

  const { filename, mimeType, sizeBytes } = parsed.data;
  if (isDangerousExtension(filename)) {
    res.status(400).json({ error: 'File type not allowed' });
    return;
  }

  const fileId = randomUUID();
  const s3Key = buildStorageKey(fileId, filename);

  await pool.query(
    `INSERT INTO files (id, workspace_id, uploaded_by, filename, mime_type, size_bytes, s3_key, status)
     VALUES ($1, $2, $3, $4, $5, $6, $7, 'pending')`,
    [fileId, req.workspaceId, req.userId, filename, mimeType, sizeBytes, s3Key]
  );

  if (usesS3Storage()) {
    const uploadUrl = await createS3PresignedUrl(s3Key, mimeType, sizeBytes);
    res.status(201).json(uploadRequestResponseSchema.parse({
      fileId,
      status: 'pending',
      uploadUrl,
      method: 'PUT',
      expiresInSeconds: PRESIGNED_URL_EXPIRES_IN,
      downloadUrl: null,
      metadataUrl: buildDownloadUrl(fileId),
    }));
    return;
  }

  res.status(201).json(uploadRequestResponseSchema.parse({
    fileId,
    status: 'pending',
    uploadUrl: null,
    uploadEndpoint: buildUploadPath(fileId),
    method: 'POST',
    downloadUrl: null,
    metadataUrl: buildDownloadUrl(fileId),
  }));
});

filesRouter.post('/upload/:id', authMiddleware, localUploadMiddleware.single('file'), async (req: Request, res: Response) => {
  const fileId = String(req.params.id);
  if (!UUID_REGEX.test(fileId)) {
    res.status(400).json({ error: 'Invalid file ID format' });
    return;
  }

  if (usesS3Storage()) {
    res.status(400).json({ error: 'Local multipart upload is only available in local development' });
    return;
  }

  if (!req.file) {
    res.status(400).json({ error: 'Missing file upload' });
    return;
  }

  const fileResult = await pool.query(
    `SELECT id, filename, mime_type, size_bytes, s3_key, status FROM files WHERE id = $1 AND workspace_id = $2`,
    [fileId, req.workspaceId]
  );
  const fileRow = fileResult.rows[0];
  if (!fileRow) {
    res.status(404).json({ error: 'File not found' });
    return;
  }

  const filePath = join(LOCAL_UPLOADS_DIR, fileRow.s3_key);
  await mkdir(dirname(filePath), { recursive: true });
  await writeFile(filePath, req.file.buffer);

  await pool.query(`UPDATE files SET status = 'uploaded', uploaded_at = NOW(), updated_at = NOW() WHERE id = $1`, [fileId]);

  res.status(200).json({
    id: fileId,
    status: 'uploaded',
    downloadUrl: buildDownloadUrl(fileId),
  });
});

filesRouter.get('/:id', authMiddleware, async (req: Request, res: Response) => {
  const fileId = String(req.params.id);
  if (!UUID_REGEX.test(fileId)) {
    res.status(400).json({ error: 'Invalid file ID format' });
    return;
  }

  const result = await pool.query(
    `SELECT id, filename, mime_type, size_bytes, s3_key, status, created_at, uploaded_at, failed_at, error_message
     FROM files WHERE id = $1 AND workspace_id = $2`,
    [fileId, req.workspaceId]
  );
  const file = result.rows[0];
  if (!file) {
    res.status(404).json({ error: 'File not found' });
    return;
  }

  res.json(fileMetadataResponseSchema.parse({
    id: file.id,
    filename: file.filename,
    mimeType: file.mime_type,
    sizeBytes: Number(file.size_bytes),
    s3Key: file.s3_key,
    status: file.status,
    createdAt: file.created_at,
    uploadedAt: file.uploaded_at ?? null,
    failedAt: file.failed_at ?? null,
    errorMessage: file.error_message ?? null,
    downloadUrl: file.status === 'uploaded' ? buildDownloadUrl(file.id) : null,
  }));
});

