    if (parent.rowCount === 0 || parent.rows[0].document_id !== documentId) return res.status(404).json({ error: 'Parent comment not found' });
    const inserted = await pool.query<CommentRow>(
      'INSERT INTO comments (id, document_id, comment_id, parent_id, author_id, content) VALUES ($1, $2, $3, $4, $5, $6) RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at',
      [randomUUID(), documentId, parent.rows[0].comment_id, parentId, req.userId!, content]
    );
