  if (existing.rowCount === 0) return res.status(404).json({ error: 'Comment not found' });
  if (existing.rows[0].workspace_id !== req.workspaceId) return res.status(403).json({ error: 'Forbidden' });

  const result = await pool.query<CommentRow>('UPDATE comments SET resolved_at = NOW(), resolved_by = $2, updated_at = NOW() WHERE id = $1 RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at', [id, req.userId]);
