});

commentsRouter.delete('/comments/:id', authMiddleware, async (req: Request, res: Response) => {
  const id = parseUuid(req.params.id);
  if (!id) return res.status(400).json({ error: 'Invalid comment id' });

  const existing = await getCommentWithWorkspace(id);
  if (existing.rowCount === 0) return res.status(404).json({ error: 'Comment not found' });
  if (existing.rows[0].workspace_id !== req.workspaceId) return res.status(403).json({ error: 'Forbidden' });

  const admin = await isWorkspaceAdmin(req.workspaceId, req.userId!);
  if (existing.rows[0].author_id !== req.userId && !admin) {
    return res.status(403).json({ error: 'Only the author or an admin can delete this comment' });
  }

  await pool.query('UPDATE comments SET deleted_at = NOW(), updated_at = NOW() WHERE id = $1', [id]);
  return res.status(204).send();
});

