   138	export async function uploadFile(file: File, onProgress?: ProgressCallback, signal?: AbortSignal): Promise<UploadResult> {
   139	  if (signal?.aborted) throw getAbortError();
   140	
   141	  const progressState: UploadProgress = { fileId: '', progress: 0, status: 'pending' };
   142	  const updateProgress = (updates: Partial<UploadProgress>) => {
   143	    Object.assign(progressState, updates);
   144	    trackUploadProgress(onProgress, { ...progressState });
   145	  };
   146	
