   148	    updateProgress({ status: 'pending', progress: 10 });
   149	    const request = await requestUpload(file, signal);
   150	    updateProgress({ fileId: request.fileId, progress: 25 });
   151	
   152	    const uploadUrl = isLocalUploadMethod(request) ? `${API_BASE}${request.uploadUrl}` : request.uploadUrl;
   153	    const method = getUploadMethod(request);
   154	    const mimeType = getUploadMimeType(file);
   155	
   156	    updateProgress({ status: 'uploading', progress: 40 });
   157	    const requestInit: RequestInit = {
   158	      method,
   159	      headers:
   160	        method === 'PUT'
   161	          ? { 'Content-Type': mimeType }
   162	          : { 'X-CSRF-Token': await getCsrfToken() },
   163	      credentials: 'include',
   164	      signal,
   165	    };
   166	
   167	    if (method === 'PUT') {
   168	      requestInit.body = file;
   169	    } else {
   170	      const formData = new FormData();
   171	      formData.append('file', file);
   172	      requestInit.body = formData;
   173	    }
   174	
   175	    const uploadRes = await uploadViaFetch(uploadUrl, requestInit);
   176	
   177	    if (!uploadRes.ok) {
   178	      throw new Error(await readErrorResponse(uploadRes, 'Failed to upload file'));
   179	    }
   180	
   181	    updateProgress({ status: 'confirming', progress: 90 });
   182	    const finalUrl = request.cdnUrl ?? (isLocalUploadMethod(request) ? request.uploadUrl : request.uploadUrl);
   183	    const result: UploadResult = {
   184	      fileId: request.fileId,
   185	      url: finalUrl,
   186	      cdnUrl: request.cdnUrl ?? finalUrl,
   187	      name: file.name,
   188	      size: file.size,
   189	      mimeType,
   190	    };
