    55	function refreshUploadPresence(): void {
    56	  if (!hasWindow()) return;
    57	
    58	  if (beforeUnloadListener) {
    59	    window.removeEventListener('beforeunload', beforeUnloadListener);
    60	    beforeUnloadListener = null;
    61	  }
    62	
    63	  if (!hasActiveUploads()) return;
    64	
    65	  beforeUnloadListener = getBeforeUnloadHandler();
    66	  window.addEventListener('beforeunload', beforeUnloadListener);
    67	}
