   109	async function handleImageUpload(
   110	  editor: Editor,
   111	  file: File,
   112	  options: ImageUploadOptions
   113	) {
   114	  const signal = options.abortController?.signal;
   115	
   116	  // Check if already aborted (e.g., user navigated away before upload started)
   117	  if (signal?.aborted) {
   118	    return;
   119	  }
   120	
   121	  options.onUploadStart?.(file);
   122	
   123	  // Generate unique upload ID for tracking navigation warnings
   124	  const uploadId = crypto.randomUUID();
   125	  registerUpload(uploadId, file.name);
   126	
   127	  // Insert image with local preview for immediate feedback
   128	  const previewUrl = URL.createObjectURL(file);
