   132	    .setImage({
   133	      src: previewUrl,
   134	      alt: file.name,
   135	      title: file.name,
   136	    })
   137	    .run();
   138	
   139	  // Revoke the preview URL once the image is replaced or upload stops
   140	  const cleanupPreview = () => URL.revokeObjectURL(previewUrl);
   141	
   142	  try {
   143	    const result = await uploadFile(
   144	      file,
   145	      (progress: UploadProgress) => {
   146	        // Update global tracker for navigation warning
   147	        updateUploadProgress(uploadId, progress.progress);
   148	      },
   149	      signal
   150	    );
   151	
   152	    // Check if aborted before updating the editor
   153	    // This prevents updating a stale editor after navigation
   154	    if (signal?.aborted) {
   155	      console.log('Image upload completed but was cancelled - not updating editor');
   156	      return;
   157	    }
   158	
   159	    const uploadedUrl = getUploadedImageUrl(result);
   160	
   161	    const { state, view } = editor;
   162	    const { doc } = state;
   163	
   164	    let imagePos: number | null = null;
   165	
   166	    doc.descendants((node: ProseMirrorNode, pos: number) => {
   167	      if (node.type.name === 'image' && node.attrs.src === previewUrl) {
   168	        imagePos = pos;
   169	        return false;
   170	      }
   171	      return true;
   172	    });
   173	
   174	    if (imagePos !== null) {
