     2	import { apiGet, apiPost, apiPatch, apiDelete } from '@/lib/api';
     3	
     4	export interface WikiDocument {
     5	  id: string;
     6	  title: string;
     7	  document_type: string;
     8	  parent_id: string | null;
     9	  position: number;
    10	  created_at: string;
    11	  updated_at: string;
    12	  created_by?: string | null;
    13	  properties?: Record<string, unknown>;
    14	  visibility: 'private' | 'workspace';
    15	}
    16	
    17	// Query keys
    18	export const documentKeys = {
    19	  all: ['documents'] as const,
    20	  lists: () => [...documentKeys.all, 'list'] as const,
    21	  list: (type: string) => [...documentKeys.lists(), type] as const,
    22	  wikiList: () => [...documentKeys.all, 'wiki'] as const,
    23	  details: () => [...documentKeys.all, 'detail'] as const,
    24	  detail: (id: string) => [...documentKeys.details(), id] as const,
    25	};
    26	
    27	// Fetch documents
    28	async function fetchDocuments(type: string = 'wiki'): Promise<WikiDocument[]> {
    29	  const res = await apiGet(`/api/documents?type=${type}`);
    30	  if (!res.ok) {
    31	    const error = new Error('Failed to fetch documents') as Error & { status: number };
    32	    error.status = res.status;
    33	    throw error;
    34	  }
    35	  return res.json();
    36	}
    37	
    38	// Create document
    39	async function createDocumentApi(data: { title: string; document_type: string; parent_id?: string | null }): Promise<WikiDocument> {
    40	  const res = await apiPost('/api/documents', data);
    41	  if (!res.ok) {
    42	    const error = new Error('Failed to create document') as Error & { status: number };
    43	    error.status = res.status;
    44	    throw error;
    45	  }
    46	  return res.json();
    47	}
    48	
    49	// Update document
    50	async function updateDocumentApi(id: string, updates: Partial<WikiDocument>): Promise<WikiDocument> {
    51	  const res = await apiPatch(`/api/documents/${id}`, updates);
    52	  if (!res.ok) {
    53	    const error = new Error('Failed to update document') as Error & { status: number };
    54	    error.status = res.status;
    55	    throw error;
    56	  }
    57	  return res.json();
    58	}
    59	
    60	// Delete document
    61	async function deleteDocumentApi(id: string): Promise<void> {
    62	  const res = await apiDelete(`/api/documents/${id}`);
    63	  if (!res.ok) {
    64	    const error = new Error('Failed to delete document') as Error & { status: number };
    65	    error.status = res.status;
    66	    throw error;
    67	  }
    68	}
    69	
    70	// Hook to get documents
    71	export function useDocumentsQuery(type: string = 'wiki') {
    72	  const queryKey = type === 'wiki' ? documentKeys.wikiList() : documentKeys.list(type);
    73	  return useQuery({
    74	    queryKey,
    75	    queryFn: () => fetchDocuments(type),
    76	    staleTime: 1000 * 60 * 5, // 5 minutes
    77	    refetchOnMount: 'always',
    78	  });
    79	}
    80	
    81	// Hook to create document with optimistic update
    82	export function useCreateDocument() {
    83	  const queryClient = useQueryClient();
    84	
    85	  return useMutation({
    86	    mutationFn: (data: { title?: string; document_type?: string; parent_id?: string | null; visibility?: 'private' | 'workspace' }) =>
    87	      createDocumentApi({
    88	        title: data.title ?? 'Untitled',
    89	        document_type: data.document_type ?? 'wiki',
    90	        parent_id: data.parent_id ?? null,
    91	      }),
    92	    onMutate: async (newDoc) => {
    93	      await queryClient.cancelQueries({ queryKey: documentKeys.lists() });
    94	      const previousDocs = queryClient.getQueryData<WikiDocument[]>(documentKeys.wikiList());
    95	
    96	      const optimisticDoc: WikiDocument = {
    97	        id: `temp-${crypto.randomUUID()}`,
    98	        title: newDoc.title ?? 'Untitled',
    99	        document_type: newDoc.document_type ?? 'wiki',
   100	        parent_id: newDoc.parent_id ?? null,
   101	        position: 0,
   102	        created_at: new Date().toISOString(),
   103	        updated_at: new Date().toISOString(),
   104	        visibility: newDoc.visibility ?? 'workspace',
   105	      };
   106	
   107	      queryClient.setQueryData<WikiDocument[]>(
   108	        documentKeys.wikiList(),
   109	        (old) => [optimisticDoc, ...(old || [])]
   110	      );
   111	
   112	      return { previousDocs, optimisticId: optimisticDoc.id };
   113	    },
   114	    onError: (_err, _newDoc, context) => {
   115	      if (context?.previousDocs) {
   116	        queryClient.setQueryData(documentKeys.wikiList(), context.previousDocs);
   117	      }
   118	    },
   119	    onSuccess: (data, _variables, context) => {
   120	      if (context?.optimisticId) {
   121	        queryClient.setQueryData<WikiDocument[]>(
   122	          documentKeys.wikiList(),
   123	          (old) => old?.map(d => d.id === context.optimisticId ? data : d) || [data]
   124	        );
   125	      }
   126	    },
   127	    onSettled: () => {
   128	      queryClient.invalidateQueries({ queryKey: documentKeys.lists() });
   129	    },
   130	  });
   131	}
   132	
   133	// Hook to update document with optimistic update
   134	export function useUpdateDocument() {
   135	  const queryClient = useQueryClient();
   136	
   137	  return useMutation({
   138	    mutationFn: ({ id, updates }: { id: string; updates: Partial<WikiDocument> }) =>
   139	      updateDocumentApi(id, updates),
   140	    onMutate: async ({ id, updates }) => {
   141	      await queryClient.cancelQueries({ queryKey: documentKeys.lists() });
   142	      const previousDocs = queryClient.getQueryData<WikiDocument[]>(documentKeys.wikiList());
   143	
   144	      queryClient.setQueryData<WikiDocument[]>(
   145	        documentKeys.wikiList(),
   146	        (old) => old?.map(d => d.id === id ? { ...d, ...updates } : d) || []
   147	      );
   148	
   149	      return { previousDocs };
   150	    },
   151	    onError: (_err, _variables, context) => {
   152	      if (context?.previousDocs) {
   153	        queryClient.setQueryData(documentKeys.wikiList(), context.previousDocs);
   154	      }
   155	    },
   156	    onSuccess: (data, { id }) => {
   157	      queryClient.setQueryData<WikiDocument[]>(
   158	        documentKeys.wikiList(),
   159	        (old) => old?.map(d => d.id === id ? data : d) || []
   160	      );
   161	    },
   162	    onSettled: () => {
   163	      queryClient.invalidateQueries({ queryKey: documentKeys.lists() });
   164	    },
   165	  });
   166	}
   167	
   168	// Hook to delete document with optimistic update
   169	export function useDeleteDocument() {
   170	  const queryClient = useQueryClient();
   171	
   172	  return useMutation({
   173	    mutationFn: (id: string) => deleteDocumentApi(id),
   174	    onMutate: async (id) => {
   175	      await queryClient.cancelQueries({ queryKey: documentKeys.lists() });
   176	      const previousDocs = queryClient.getQueryData<WikiDocument[]>(documentKeys.wikiList());
   177	
   178	      queryClient.setQueryData<WikiDocument[]>(
   179	        documentKeys.wikiList(),
   180	        (old) => old?.filter(d => d.id !== id) || []
   181	      );
   182	
   183	      return { previousDocs };
   184	    },
   185	    onError: (_err, _id, context) => {
   186	      if (context?.previousDocs) {
   187	        queryClient.setQueryData(documentKeys.wikiList(), context.previousDocs);
   188	      }
   189	    },
   190	    onSettled: () => {
   191	      queryClient.invalidateQueries({ queryKey: documentKeys.lists() });
   192	    },
   193	  });
   194	}
   195	
   196	// Compatibility hook that matches the old useDocuments interface
   197	export function useDocuments() {
   198	  const { data: documents = [], isLoading: loading, refetch } = useDocumentsQuery('wiki');
   199	  const createMutation = useCreateDocument();
   200	  const updateMutation = useUpdateDocument();
   201	  const deleteMutation = useDeleteDocument();
   202	
   203	  const createDocument = async (parentId?: string): Promise<WikiDocument | null> => {
   204	    try {
   205	      return await createMutation.mutateAsync({ parent_id: parentId });
   206	    } catch {
   207	      return null;
   208	    }
   209	  };
   210	
   211	  const updateDocument = async (id: string, updates: Partial<WikiDocument>): Promise<WikiDocument | null> => {
   212	    try {
   213	      return await updateMutation.mutateAsync({ id, updates });
   214	    } catch {
   215	      return null;
   216	    }
   217	  };
   218	
   219	  const deleteDocument = async (id: string): Promise<boolean> => {
   220	    try {
   221	      await deleteMutation.mutateAsync(id);
   222	      return true;
   223	    } catch {
   224	      return false;
   225	    }
   226	  };
   227	
   228	  const refreshDocuments = async (): Promise<void> => {
   229	    await refetch();
   230	  };
   231	
   232	  return {
   233	    documents,
   234	    loading,
   235	    createDocument,
   236	    updateDocument,
   237	    deleteDocument,
   238	    refreshDocuments,
   239	  };
   240	}
