{"success":true,"content":"     1	import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
     2	import { apiGet, apiPost, apiPatch } from '@/lib/api';
     3	import type { CascadeWarning, IncompleteChild, BelongsTo, BelongsToType } from '@ship/shared';
     4	
     5	// Custom error type for cascade warning (409 response)
     6	export class CascadeWarningError extends Error {
     7	  status = 409;
     8	  warning: CascadeWarning;
     9	
    10	  constructor(warning: CascadeWarning) {
    11	    super(warning.message);
    12	    this.name = 'CascadeWarningError';
    13	    this.warning = warning;
    14	  }
    15	}
    16	
    17	// Type guard for CascadeWarningError
    18	export function isCascadeWarningError(error: unknown): error is CascadeWarningError {
    19	  return error instanceof CascadeWarningError;
    20	}
    21	
    22	// Re-export for convenience
    23	export type { CascadeWarning, IncompleteChild, BelongsTo, BelongsToType };
    24	
    25	export interface Issue {
    26	  id: string;
    27	  title: string;
    28	  state: string;
    29	  priority: string;
    30	  ticket_number: number;
    31	  display_id: string;
    32	  assignee_id: string | null;
    33	  assignee_name: string | null;
    34	  assignee_archived?: boolean;
    35	  estimate: number | null;
    36	  // belongs_to array contains all associations (program, sprint, project, parent)
    37	  belongs_to: BelongsTo[];
    38	  source: 'internal' | 'external';
    39	  rejection_reason: string | null;
    40	  created_at?: string;
    41	  updated_at?: string;
    42	  created_by?: string;
    43	  started_at?: string | null;
    44	  completed_at?: string | null;
    45	  cancelled_at?: string | null;
    46	  reopened_at?: string | null;
    47	  converted_from_id?: string | null;
    48	}
    49	
    50	// Helper to extract association ID by type
    51	export function getAssociationId(issue: Issue, type: BelongsToType): string | null {
    52	  const association = issue.belongs_to?.find(a => a.type === type);
    53	  return association?.id ?? null;
    54	}
    55	
    56	// Helper to get program ID from belongs_to
    57	export function getProgramId(issue: Issue): string | null {
    58	  return getAssociationId(issue, 'program');
    59	}
    60	
    61	// Helper to get sprint ID from belongs_to
    62	export function getSprintId(issue: Issue): string | null {
    63	  return getAssociationId(issue, 'sprint');
    64	}
    65	
    66	// Helper to get project ID from belongs_to
    67	export function getProjectId(issue: Issue): string | null {
    68	  return getAssociationId(issue, 'project');
    69	}
    70	
    71	// Helper to get association title by type (e.g., program name)
    72	export function getAssociationTitle(issue: Issue, type: BelongsToType): string | null {
    73	  const association = issue.belongs_to?.find(a => a.type === type);
    74	  return association?.title ?? null;
    75	}
    76	
    77	// Helper to get program title from belongs_to
    78	export function getProgramTitle(issue: Issue): string | null {
    79	  return getAssociationTitle(issue, 'program');
    80	}
    81	
    82	// Helper to get project title from belongs_to
    83	export function getProjectTitle(issue: Issue): string | null {
    84	  return getAssociationTitle(issue, 'project');
    85	}
    86	
    87	// Helper to get sprint title from belongs_to
    88	export function getSprintTitle(issue: Issue): string | null {
    89	  return getAssociationTitle(issue, 'sprint');
    90	}
    91	
    92	// Filter interface for locked context
    93	export interface IssueFilters {
    94	  programId?: string;
    95	  projectId?: string;
    96	  sprintId?: string;
    97	}
    98	
    99	// Query keys
   100	export const issueKeys = {
   101	  all: ['issues'] as const,
   102	  lists: () => [...issueKeys.all, 'list'] as const,
   103	  list: (filters?: IssueFilters) => [...issueKeys.lists(), filters] as const,
   104	  details: () => [...issueKeys.all, 'detail'] as const,
   105	  detail: (id: string) => [...issueKeys.details(), id] as const,
   106	};
   107	
   108	// Transform API issue response to Issue type
   109	function transformIssue(apiIssue: Record<string, unknown>): Issue {
   110	  const belongs_to = (apiIssue.belongs_to as BelongsTo[]) || [];
   111	
   112	  return {
   113	    ...apiIssue,
   114	    belongs_to,
   115	  } as Issue;
   116	}
   117	
   118	// Fetch issues with optional filters
   119	async function fetchIssues(filters?: IssueFilters): Promise<Issue[]> {
   120	  const params = new URLSearchParams();
   121	  if (filters?.programId) params.append('program_id', filters.programId);
   122	  if (filters?.sprintId) params.append('sprint_id', filters.sprintId);
   123	  // Note: projectId filtering is done client-side via belongs_to array
   124	
   125	  const queryString = params.toString();
   126	  const url = queryString ? `/api/issues?${queryString}` : '/api/issues';
   127	
   128	  const res = await apiGet(url);
   129	  if (!res.ok) {
   130	    const error = new Error('Failed to fetch issues') as Error & { status: number };
   131	    error.status = res.status;
   132	    throw error;
   133	  }
   134	  const data = await res.json();
   135	  let issues = (data as Record<string, unknown>[]).map(transformIssue);
   136	
   137	  // Client-side filter for projectId (API doesn't support direct project_id param)
   138	  if (filters?.projectId) {
   139	    issues = issues.filter(issue => {
   140	      const projectAssoc = issue.belongs_to?.find(a => a.type === 'project');
   141	      return projectAssoc?.id === filters.projectId;
   142	    });
   143	  }
   144	
   145	  return issues;
   146	}
   147	
   148	// Create issue
   149	interface CreateIssueData {
   150	  title?: string;
   151	  belongs_to?: BelongsTo[];
   152	}
   153	
   154	async function createIssueApi(data: CreateIssueData): Promise<Issue> {
   155	  const apiData: Record<string, unknown> = { title: data.title ?? 'Untitled' };
   156	  if (data.belongs_to && data.belongs_to.length > 0) {
   157	    apiData.belongs_to = data.belongs_to;
   158	  }
   159	
   160	  const res = await apiPost('/api/issues', apiData);
   161	  if (!res.ok) {
   162	    const error = new Error('Failed to create issue') as Error & { status: number };
   163	    error.status = res.status;
   164	    throw error;
   165	  }
   166	  const apiIssue = await res.json();
   167	  return transformIssue(apiIssue);
   168	}
   169	
   170	// Update issue
   171	async function updateIssueApi(id: string, updates: Partial<Issue>): Promise<Issue> {
   172	  // API accepts belongs_to directly - no conversion needed
   173	  const res = await apiPatch(`/api/issues/${id}`, updates);
   174	  if (!res.ok) {
   175	    // Check for cascade warning (409 with incomplete_children)
   176	    if (res.status === 409) {
   177	      const body = await res.json();
   178	      if (body.error === 'incomplete_children') {
   179	        throw new CascadeWarningError(body as CascadeWarning);
   180	      }
   181	    }
