  mutationFn: (variables: TVariables) => Promise<TData>
) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn,
    onSuccess: async () => {
      await queryClient.invalidateQueries({ queryKey: commentKeys.document(documentId) });
    },
  });
}

export function useCommentsQuery(documentId: string | undefined) {
  return useQuery<CommentThread[]>({
    queryKey: commentKeys.document(documentId),
    queryFn: async () => {
      if (!documentId) return [];
      const response = await apiGet(`/api/documents/${documentId}/comments`);
      if (!response.ok) throw new Error('Failed to fetch comments');
      const data = await parseCommentsResponse(response);
      return data.comments;
    },
    enabled: !!documentId,
  });
}

