     2	 * Global upload tracker for navigation warnings
     3	 * Used by both React components (via subscription) and non-React code (TipTap plugins)
     4	 */
     5	
     6	export interface UploadInfo {
     7	  id: string;
     8	  filename: string;
     9	  progress: number;
    10	  active: boolean;
    11	}
    12	
    13	export interface UploadNavigationWarningState {
    14	  isBlocked: boolean;
    15	  uploadCount: number;
    16	  activeUploads: UploadInfo[];
    17	  proceed: () => void;
    18	  stay: () => void;
    19	}
    20	
    21	export interface UploadTrackerSnapshot {
    22	  uploadCount: number;
    23	  activeUploads: UploadInfo[];
    24	}
    25	
    26	export interface UploadTrackerListenerState extends UploadTrackerSnapshot {
    27	  hasActiveUploads: boolean;
    28	}
    29	
    30	const activeUploads = new Map<string, UploadInfo>();
    31	const listeners = new Set<() => void>();
    32	let beforeUnloadListener: ((event: BeforeUnloadEvent) => void) | null = null;
    33	
    34	function getUploadMessage(uploadCount: number): string {
    35	  if (uploadCount <= 0) return '';
    36	  return uploadCount === 1 ? '1 upload is still in progress.' : `${uploadCount} uploads are still in progress.`;
    37	}
    38	
    39	function cloneUpload(upload: UploadInfo): UploadInfo {
    40	  return { ...upload };
    41	}
    42	
    43	function hasWindow(): boolean {
    44	  return typeof window !== 'undefined';
    45	}
    46	
    47	function notifyListeners(): void {
    48	  listeners.forEach((listener) => listener());
    49	}
    50	
    51	function getBeforeUnloadHandler() {
    52	  return (event: BeforeUnloadEvent) => {
    53	    if (!hasActiveUploads()) return;
    54	    event.preventDefault();
    55	    event.returnValue = getUploadMessage(getUploadCount());
    56	    return event.returnValue;
    57	  };
    58	}
    59	
    60	function refreshUploadPresence(): void {
    61	  if (!hasWindow()) return;
    62	
    63	  if (beforeUnloadListener) {
    64	    window.removeEventListener('beforeunload', beforeUnloadListener);
    65	    beforeUnloadListener = null;
    66	  }
    67	
    68	  if (!hasActiveUploads()) return;
    69	
    70	  beforeUnloadListener = getBeforeUnloadHandler();
    71	  window.addEventListener('beforeunload', beforeUnloadListener);
    72	}
    73	
    74	export function registerUpload(id: string, filename: string): void {
    75	  activeUploads.set(id, { id, filename, progress: 0, active: true });
    76	  refreshUploadPresence();
    77	  notifyListeners();
    78	}
    79	
    80	export function updateUploadProgress(id: string, progress: number): void {
    81	  const upload = activeUploads.get(id);
    82	  if (!upload) return;
    83	
    84	  upload.progress = progress;
    85	  upload.active = true;
    86	  refreshUploadPresence();
    87	  notifyListeners();
    88	}
    89	
    90	export function markUploadInactive(id: string): void {
    91	  const upload = activeUploads.get(id);
    92	  if (!upload) return;
    93	
    94	  upload.active = false;
    95	  refreshUploadPresence();
    96	  notifyListeners();
    97	}
    98	
    99	export function unregisterUpload(id: string): void {
   100	  activeUploads.delete(id);
   101	  refreshUploadPresence();
   102	  notifyListeners();
   103	}
   104	
   105	export function clearUploads(): void {
   106	  activeUploads.clear();
   107	  refreshUploadPresence();
   108	  notifyListeners();
   109	}
   110	
   111	export function getUploadCount(): number {
   112	  return Array.from(activeUploads.values()).filter((upload) => upload.active).length;
   113	}
   114	
   115	export function getActiveUploads(): UploadInfo[] {
   116	  return Array.from(activeUploads.values())
   117	    .filter((upload) => upload.active)
   118	    .map(cloneUpload);
   119	}
   120	
   121	export function hasActiveUploads(): boolean {
   122	  return getUploadCount() > 0;
   123	}
   124	
   125	export function getUploadSnapshot(): UploadTrackerSnapshot {
   126	  return {
   127	    uploadCount: getUploadCount(),
   128	    activeUploads: getActiveUploads(),
   129	  };
   130	}
   131	
   132	export function subscribeToUploads(listener: () => void): () => void {
   133	  listeners.add(listener);
   134	  return () => listeners.delete(listener);
   135	}
   136	
   137	export function bindUploadNavigationWarning(onBeforeUnload: (event: BeforeUnloadEvent) => void): () => void {
   138	  if (!hasWindow()) return () => undefined;
   139	  window.addEventListener('beforeunload', onBeforeUnload);
   140	  return () => window.removeEventListener('beforeunload', onBeforeUnload);
   141	}
   142	
   143	export function getUploadTrackerListenerState(): UploadTrackerListenerState {
   144	  return {
   145	    ...getUploadSnapshot(),
   146	    hasActiveUploads: hasActiveUploads(),
   147	  };
   148	}
