function isLocalUploadMethod(request: UploadRequestResult): boolean {
  return request.isLocalUpload ?? request.uploadUrl.startsWith('/api/files/upload');
}

function createProgressState(fileId = ''): UploadProgress {
  return { fileId, progress: 0, status: 'pending' };
}

function emitProgress(onProgress: ProgressCallback | undefined, state: UploadProgress, updates: Partial<UploadProgress>): UploadProgress {
  const nextState = { ...state, ...updates };
  trackUploadProgress(onProgress, nextState);
  return nextState;
}

export function createUploadProgressTracker(onProgress?: ProgressCallback) {
  let state = createProgressState();
  return {
    update(updates: Partial<UploadProgress>) {
      state = emitProgress(onProgress, state, updates);
    },
    getState() {
      return { ...state };
    },
  };
}

