    14	// CSRF token cache for state-changing requests
    15	let csrfToken: string | null = null;
    16	
    17	// Helper: Check if response has JSON content type
    18	function isJsonResponse(response: Response): boolean {
    19	  const contentType = response.headers.get('content-type');
    20	  return contentType?.includes('application/json') ?? false;
    21	}
    22	
    23	/**
    24	 * Handle session expiration - redirect to login with expired=true flag
    25	 *
    26	 * IMPORTANT: Only call this for actual session expiration (SESSION_EXPIRED error code),
    27	 * NOT for missing sessions (UNAUTHORIZED). Fresh visitors with no session should get
    28	 * a clean redirect via ProtectedRoute without the "session expired" message.
    29	 *
    30	 * The expired=true flag triggers the yellow "session expired" modal on the login page.
    31	 * Fresh visitors shouldn't see this - it would be confusing UX.
    32	 *
    33	 * Returns `never` because it always redirects or throws.
    34	 */
    35	function handleSessionExpired(): never {
    36	  // Don't redirect to login when offline - let TanStack Query handle retries
    37	  if (!navigator.onLine) {
    38	    throw new Error('Network offline - request failed');
    39	  }
    40	  // Don't redirect on public routes like /invite - they work without authentication
    41	  if (window.location.pathname.startsWith('/invite')) {
    42	    throw new Error('Session check failed - continuing on public route');
    43	  }
    44	  if (window.location.pathname !== '/login') {
    45	    const returnTo = encodeURIComponent(
    46	      window.location.pathname + window.location.search + window.location.hash
    47	    );
    48	    window.location.href = `/login?expired=true&returnTo=${returnTo}`;
    49	  }
    50	  // Throw to satisfy TypeScript's `never` type (redirect is async)
    51	  throw new Error('Session expired - redirecting to login');
    52	}
