    54	async function ensureCsrfToken(): Promise<string> {
    55	  if (!csrfToken) {
    56	    const response = await fetch(`${API_URL}/api/csrf-token`, {
    57	      credentials: 'include',
    58	    });
    59	    if (!response.ok || !isJsonResponse(response)) {
    60	      // Session likely expired - redirect to login
    61	      if (response.status === 401 || response.status === 403) {
    62	        handleSessionExpired(); // never returns
    63	      }
    64	      throw new Error('Failed to get CSRF token');
    65	    }
    66	    const data = await response.json();
    67	    csrfToken = data.token;
    68	  }
    69	  return csrfToken!;
    70	}
