     2	 * TipTap Image Upload Extension
     3	 * Handles paste/drop events for images and manages upload flow
     4	 */
     5	import { Extension } from '@tiptap/core';
     6	import { Plugin, PluginKey } from '@tiptap/pm/state';
     7	import { Node as ProseMirrorNode } from '@tiptap/pm/model';
     8	import { Editor } from '@tiptap/react';
     9	import { uploadFile, isImageFile, type UploadProgress } from '@/services/upload.js';
    10	import { registerUpload, updateUploadProgress, unregisterUpload } from '@/services/uploadTracker.js';
    11	
    12	function resolveUploadUrl(url: string) {
    13	  if (url.startsWith('http://') || url.startsWith('https://') || url.startsWith('data:')) {
    14	    return url;
    15	  }
    16	
    17	  return `${import.meta.env.VITE_API_URL ?? ''}${url}`;
    18	}
    19	
    20	function getUploadedImageUrl(result: Awaited<ReturnType<typeof uploadFile>>): string {
    21	  return resolveUploadUrl(result.cdnUrl || result.url);
    22	}
    23	
    24	export interface ImageUploadOptions {
    25	  /**
    26	   * Callback when an image upload starts
    27	   */
    28	  onUploadStart?: (file: File) => void;
    29	  /**
    30	   * Callback when an image upload completes
    31	   */
    32	  onUploadComplete?: (cdnUrl: string) => void;
    33	  /**
    34	   * Callback when an image upload fails
    35	   */
    36	  onUploadError?: (error: Error) => void;
    37	  /**
    38	   * AbortController for cancelling uploads on navigation/cleanup
    39	   * When aborted, pending uploads will be cancelled and won't update the document
    40	   */
    41	  abortController?: AbortController;
    42	}
    43	
    44	export const ImageUploadExtension = Extension.create<ImageUploadOptions>({
    45	  name: 'imageUpload',
    46	
    47	  addOptions() {
    48	    return {
    49	      onUploadStart: undefined,
    50	      onUploadComplete: undefined,
    51	      onUploadError: undefined,
    52	      abortController: undefined,
    53	    };
    54	  },
    55	
    56	  addProseMirrorPlugins() {
    57	    const editor = this.editor as Editor;
    58	    const options = this.options;
    59	
    60	    return [
    61	      new Plugin({
    62	        key: new PluginKey('imageUpload'),
    63	        props: {
    64	          handlePaste(view, event) {
    65	            const items = Array.from(event.clipboardData?.items || []);
    66	            const imageItem = items.find(
    67	              (item) => item.type.startsWith('image/')
    68	            );
    69	
    70	            if (!imageItem) {
    71	              return false;
    72	            }
    73	
    74	            event.preventDefault();
    75	
    76	            const file = imageItem.getAsFile();
    77	            if (!file) return false;
    78	
    79	            handleImageUpload(editor, file, options);
    80	            return true;
    81	          },
    82	
    83	          handleDrop(view, event) {
    84	            const files = Array.from(event.dataTransfer?.files || []);
    85	            const imageFiles = files.filter((file) => isImageFile(file.type));
    86	
    87	            if (imageFiles.length === 0) {
    88	              return false;
    89	            }
    90	
    91	            event.preventDefault();
    92	
    93	            // Upload all dropped images
    94	            imageFiles.forEach((file) => {
    95	              handleImageUpload(editor, file, options);
    96	            });
    97	
    98	            return true;
    99	          },
   100	        },
   101	      }),
   102	    ];
   103	  },
   104	});
   105	
   106	/**
   107	 * Handle image upload and insertion into editor
   108	 */
   109	async function handleImageUpload(
   110	  editor: Editor,
   111	  file: File,
   112	  options: ImageUploadOptions
   113	) {
   114	  const signal = options.abortController?.signal;
   115	
   116	  // Check if already aborted (e.g., user navigated away before upload started)
   117	  if (signal?.aborted) {
   118	    return;
   119	  }
   120	
   121	  options.onUploadStart?.(file);
   122	
   123	  // Generate unique upload ID for tracking navigation warnings
   124	  const uploadId = crypto.randomUUID();
   125	  registerUpload(uploadId, file.name);
   126	
   127	  // Insert image with local preview for immediate feedback
   128	  const previewUrl = URL.createObjectURL(file);
   129	  editor
   130	    .chain()
   131	    .focus()
   132	    .setImage({
   133	      src: previewUrl,
   134	      alt: file.name,
   135	      title: file.name,
   136	    })
   137	    .run();
   138	
   139	  // Revoke the preview URL once the image is replaced or upload stops
   140	  const cleanupPreview = () => URL.revokeObjectURL(previewUrl);
   141	
   142	  try {
   143	    const result = await uploadFile(
   144	      file,
   145	      (progress: UploadProgress) => {
   146	        // Update global tracker for navigation warning
   147	        updateUploadProgress(uploadId, progress.progress);
   148	      },
   149	      signal
   150	    );
   151	
   152	    // Check if aborted before updating the editor
   153	    // This prevents updating a stale editor after navigation
   154	    if (signal?.aborted) {
   155	      console.log('Image upload completed but was cancelled - not updating editor');
   156	      return;
   157	    }
   158	
   159	    const uploadedUrl = getUploadedImageUrl(result);
   160	
   161	    const { state, view } = editor;
   162	    const { doc } = state;
   163	
   164	    let imagePos: number | null = null;
   165	
   166	    doc.descendants((node: ProseMirrorNode, pos: number) => {
   167	      if (node.type.name === 'image' && node.attrs.src === previewUrl) {
   168	        imagePos = pos;
   169	        return false;
   170	      }
   171	      return true;
   172	    });
   173	
   174	    if (imagePos !== null) {
   175	      const transaction = state.tr.setNodeMarkup(imagePos, undefined, {
   176	        ...doc.nodeAt(imagePos)?.attrs,
   177	        src: uploadedUrl,
   178	      });
   179	      view.dispatch(transaction);
   180	    }
   181	
   182	    // If the preview node is no longer present, insert the persisted image URL
   183	    if (imagePos === null && !signal?.aborted) {
   184	      editor.chain().focus().setImage({ src: uploadedUrl, alt: file.name, title: file.name }).run();
   185	    }
   186	
   187	    cleanupPreview();
   188	    // Upload complete - unregister from tracker
   189	    unregisterUpload(uploadId);
   190	    options.onUploadComplete?.(uploadedUrl);
   191	  } catch (error) {
   192	    // Upload failed - unregister from tracker
   193	    unregisterUpload(uploadId);
   194	    cleanupPreview();
   195	    // Don't report cancellation as an error - it's intentional
   196	    if (error instanceof DOMException && error.name === 'AbortError') {
   197	      console.log('Image upload cancelled');
   198	      return;
   199	    }
   200	
   201	    console.error('Image upload failed:', error);
   202	    options.onUploadError?.(
   203	      error instanceof Error ? error : new Error('Upload failed')
   204	    );
   205	
   206	    // Optionally remove the failed image or show error state
   207	    // For now, leave the preview as fallback
   208	  }
   209	}
   210	
   211	/**
   212	 * Convert a File to a data URL
   213	 */
   214	function fileToDataUrl(file: File): Promise<string> {
   215	  return new Promise((resolve, reject) => {
   216	    const reader = new FileReader();
   217	    reader.onload = () => resolve(reader.result as string);
   218	    reader.onerror = reject;
   219	    reader.readAsDataURL(file);
   220	  });
   221	}
   222	
   223	/**
   224	 * Trigger file picker for image upload
   225	 */
   226	export function triggerImageUpload(
   227	  editor: Editor,
   228	  options: ImageUploadOptions = {}
   229	) {
   230	  // Check if already aborted
   231	  if (options.abortController?.signal?.aborted) {
   232	    return;
   233	  }
   234	
   235	  const input = document.createElement('input');
   236	  input.type = 'file';
   237	  input.accept = 'image/*';
   238	  input.multiple = true;
   239	
   240	  input.onchange = () => {
   241	    // Check again in case it was aborted while file picker was open
   242	    if (options.abortController?.signal?.aborted) {
   243	      return;
   244	    }
   245	    const files = Array.from(input.files || []);
   246	    files.forEach((file) => {
   247	      handleImageUpload(editor, file, options);
   248	    });
   249	  };
   250	
   251	  input.click();
   252	}
