it('POST /api/files/upload-request returns the local upload contract and persists pending metadata', async () => {
  expect(usesS3Storage()).toBe(false);

  const requestRes = await request(app)
    .post('/api/files/upload-request')
    .set('Cookie', sessionCookie)
    .set('x-csrf-token', csrfToken)
    .send({
      filename: 'test.png',
      mimeType: 'image/png',
      sizeBytes: 1024,
    });

  expect(requestRes.status).toBe(201);
  expect(requestRes.body).toMatchObject({
    fileId: expect.any(String),
    status: 'pending',
    uploadUrl: null,
    uploadEndpoint: expect.stringContaining(`/api/files/upload/${requestRes.body.fileId}`),
    method: 'POST',
    expiresInSeconds: null,
    downloadUrl: null,
    metadataUrl: `/api/files/${requestRes.body.fileId}`,
  });
  expect(requestRes.body).not.toHaveProperty('s3Key');

  testFileId = requestRes.body.fileId;

  const dbResult = await pool.query('SELECT * FROM files WHERE id = $1', [testFileId]);
  expect(dbResult.rows).toHaveLength(1);
  expect(dbResult.rows[0]).toMatchObject({
    status: 'pending',
    filename: 'test.png',
    mime_type: 'image/png',
    size_bytes: 1024,
  });

  const invalidUploadRes = await request(app)
    .post('/api/files/upload')
    .set('Cookie', sessionCookie)
    .set('x-csrf-token', csrfToken)
    .send({
      fileId: 'not-a-uuid',
      filename: 'uuid-test.png',
      mimeType: 'image/png',
      sizeBytes: 1024,
    });

  expect(invalidUploadRes.status).toBe(400);
  expect(invalidUploadRes.body.error).toBe('Invalid input');
});

