filesRouter.post('/upload/:id', authMiddleware, async (req: Request, res: Response) => {
  const fileId = String(req.params.id);
  if (!UUID_REGEX.test(fileId)) {
    res.status(400).json({ error: 'Invalid file ID format' });
    return;
  }

  const result = await pool.query(
    `SELECT id, filename, mime_type, size_bytes, s3_key, status, created_at, uploaded_at, failed_at, error_message
     FROM files WHERE id = $1 AND workspace_id = $2`,
    [fileId, req.workspaceId]
  );
  const file = result.rows[0];
  if (!file) {
    res.status(404).json({ error: 'File not found' });
    return;
  }

  if (usesS3Storage()) {
    res.status(400).json({ error: 'Local upload endpoint is disabled when S3 storage is enabled' });
    return;
  }

  const chunks: Buffer[] = [];
  const contentType = String(req.headers['content-type'] || '');
  const boundaryMatch = contentType.match(/boundary=(?:(?:"([^"]+)")|([^;]+))/i);
  if (!boundaryMatch) {
    res.status(400).json({ error: 'Missing multipart boundary' });
    return;
  }
  const boundary = Buffer.from(`--${boundaryMatch[1] || boundaryMatch[2]}`);
  const body = await new Promise<Buffer>((resolve, reject) => {
    req.on('data', (chunk) => chunks.push(Buffer.from(chunk)));
    req.on('end', () => resolve(Buffer.concat(chunks)));
    req.on('error', reject);
  });

  const fileMarker = Buffer.from('name="file"');
  const headerEnd = body.indexOf(Buffer.from('\r\n\r\n'), body.indexOf(fileMarker));
  const nextBoundary = body.indexOf(boundary, headerEnd + 4);
  if (headerEnd === -1 || nextBoundary === -1) {
    res.status(400).json({ error: 'Invalid multipart payload' });
    return;
  }
  const fileBuffer = body.slice(headerEnd + 4, nextBoundary - 2);
  const uploadPath = getLocalUploadPath(fileId, file.filename);
  writeFileSync(uploadPath, fileBuffer);

  await pool.query(
    `UPDATE files
     SET status = 'uploaded', uploaded_at = now(), error_message = NULL
     WHERE id = $1 AND workspace_id = $2`,
    [fileId, req.workspaceId]
  );

  res.status(200).json({
    fileId,
    status: 'uploaded',
    downloadUrl: buildDownloadUrl(fileId),
    cdnUrl: buildDownloadUrl(fileId),
  });
});

